/**
 * VideoTracker tooltip helper.
 * Shows a nice tooltip bubble on hover/focus for elements with:
 * - .vt-goal-dot
 * - data-vt-tooltip="..."
 *
 * Accessible:
 * - focus shows tooltip
 * - ESC hides tooltip
 *
 * @module     mod_videotracker/tooltip
 * @copyright  2026 LearnPlug
 * @license    http://www.gnu.org/copyleft/gpl.html GNU GPL v3 or later
 */
export const init = () => {
    const dots = Array.from(document.querySelectorAll('.mod_videotracker .vt-goal-dot'));
    if (!dots.length) {
        return;
    }

    const show = (dot) => {
        const wrap = dot.closest('.vt-goal-wrap');
        const tip = wrap ? wrap.querySelector('.vt-tooltip') : null;
        if (!tip) {
            return;
        }

        tip.classList.add('is-visible');
    };

    const hide = (dot) => {
        const wrap = dot.closest('.vt-goal-wrap');
        const tip = wrap ? wrap.querySelector('.vt-tooltip') : null;
        if (!tip) {
            return;
        }

        tip.classList.remove('is-visible');
    };

    dots.forEach((dot) => {
        const text = dot.getAttribute('data-vt-tooltip') || '';
        const wrap = dot.closest('.vt-goal-wrap');
        const tip = wrap ? wrap.querySelector('.vt-tooltip') : null;
        if (tip && text) {
            tip.textContent = text;
        }

        // Make it focusable for keyboard users.
        dot.setAttribute('tabindex', '0');
        dot.setAttribute('role', 'button');
        dot.setAttribute('aria-label', text || 'Meta de conclusão');

        dot.addEventListener('mouseenter', () => show(dot));
        dot.addEventListener('mouseleave', () => hide(dot));
        dot.addEventListener('focus', () => show(dot));
        dot.addEventListener('blur', () => hide(dot));

        dot.addEventListener('keydown', (e) => {
            if (e.key === 'Escape') {
                hide(dot);
                dot.blur();
            }
        });
    });

    // Global ESC closes any tooltip.
    document.addEventListener('keydown', (e) => {
        if (e.key !== 'Escape') {
            return;
        }

        dots.forEach((dot) => hide(dot));
    });
};
